// Pico Potentiometer & LED
// Read potentiometer on GP26 (ADC0), dim LED on GP15 via PWM.

#include <Arduino.h>

const int POT_PIN = 26;   // GP26 = ADC0
const int LED_PIN = 15;   // GP15 (PWM capable)

void setup() {
  pinMode(LED_PIN, OUTPUT);
  analogReadResolution(12);   // RP2040 has 12-bit ADC (0-4095)
  Serial.begin(115200);
  delay(100);
  Serial.println("Pico Potentiometer & LED ready");
}

void loop() {
  int potValue = analogRead(POT_PIN);          // 0 - 4095
  int pwmValue = map(potValue, 0, 4095, 0, 255);

  analogWrite(LED_PIN, pwmValue);

  Serial.print("Pot: ");
  Serial.print(potValue);
  Serial.print("  PWM: ");
  Serial.println(pwmValue);

  delay(100);
}
